const MAX: usize = 1024;
const MIN: usize = 0;

pub trait Frobable {
    fn frob(&self) -> String;
    fn frob_twice(&self) -> String {
        let a = self.frob();
        let b = self.frob();
        format!("{a}{b}")
    }
    fn name(&self) -> &str;
}

impl Foo {
    pub fn double(&self) -> u32 {
        self.value
            .checked_mul(2)
            .unwrap_or(u32::MAX)
    }
}

impl Foo {
    pub fn triple(&self) -> u32 {
        self.value
            .checked_mul(3)
            .unwrap_or(u32::MAX)
    }
}

